using namespace std;

class Solution {
public:
    vector<int> maxDepthAfterSplit(string seq) {
        vector<int> result(seq.size());
        stack<int> stk;
        int a_depth = 0, b_depth = 0;

        for (int i = 0; i < seq.size(); ++i) {
            if (seq[i] == '(') {
                if (a_depth <= b_depth) {
                    stk.push(0);
                    a_depth++;
                } else {
                    stk.push(1);
                    b_depth++;
                }
            } else {
                int assign = stk.top();
                stk.pop();
                result[i] = assign;
                if (assign == 0) {
                    a_depth--;
                } else {
                    b_depth--;
                }
            }
        }
        return result;
    }
};

